function ReportPage({data,onBack}){
  const[html,setHtml]=useState("");
  const[loading,setLoading]=useState(true);
  const[dots,setDots]=useState("");
  const called=useRef(false);
  useEffect(()=>{const iv=setInterval(()=>setDots(d=>d.length>=3?"":d+"."),400);return()=>clearInterval(iv);},[]);
  useEffect(()=>{
    if(called.current)return; called.current=true;
    (async()=>{
      try{
        const r=await fetch("https://api.anthropic.com/v1/messages",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:4000,messages:[{role:"user",content:"서울 강남구 역삼1동 소형카페(15평) 입지분석 보고서를 HTML로 작성. 보증금8000만 월세350만 배달전문. 데이터:유동인구42만,카페187개,월매출2800만,객단가6200원,테이크아웃62%. 추천:1위역삼동823-12(87점)2위735-8(83점)3위612-3(79점). 순수HTML만. 코드블록없이. 인라인스타일. 요약카드+TOP3+상권+배달전략+리스크+경쟁현황."}]})});
        if(r.ok){const d=await r.json();const t=(d.content||[]).map(c=>c.text||"").join("").replace(/```[a-z]*/gi,"").replace(/```/g,"").trim();if(t.length>200){setHtml(t);setLoading(false);return;}}
      }catch(e){console.log("API fallback:",e);}
      /* fallback with 2s delay for realism */
      await new Promise(r=>setTimeout(r,2000));
      setHtml(FALLBACK);setLoading(false);
    })();
  },[]);
  return(<div style={{height:"100%",display:"flex",flexDirection:"column",background:"#FAFAF8"}}>
    <SBar/>
    <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"12px 20px",borderBottom:"1px solid #eee",background:"#fff",flexShrink:0}}>
      <button onClick={onBack} style={{background:"none",border:"none",cursor:"pointer",padding:4}}><svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke={T1} strokeWidth="2.2" strokeLinecap="round"><polyline points="15 18 9 12 15 6"/></svg></button>
      <span style={{fontSize:17,fontWeight:700,color:T1}}>강남구 역삼1동 카페 분석</span>
      <button style={{background:B,color:"#fff",border:"none",padding:"8px 14px",borderRadius:20,fontSize:12,fontWeight:600,cursor:"pointer",display:"flex",alignItems:"center",gap:4}}><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2"><path d="M21 15v4a2 2 0 01-2 2H5a2 2 0 01-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>PDF로 다운 받기</button>
    </div>
    {loading?(<div style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",background:"#fff"}}><div style={{width:48,height:48,borderRadius:24,border:"3px solid #E8F0FE",borderTopColor:B,animation:"rspin .8s linear infinite"}}/><p style={{fontSize:15,fontWeight:600,color:T1,marginTop:20}}>AI가 보고서를 작성하고 있어요{dots}</p><p style={{fontSize:13,color:T2,marginTop:6}}>잠시만 기다려 주세요</p><style>{`@keyframes rspin{to{transform:rotate(360deg)}}`}</style></div>
    ):(<div style={{flex:1,overflow:"auto",padding:"20px",fontSize:14,lineHeight:1.7,color:"#5C5C58",fontFamily:"inherit"}} dangerouslySetInnerHTML={{__html:html}}/>)}
  </div>);
}
/* ── APP ── */
export default function App(){
  const[pg,sPg]=useState("main");
  const[tr,sTr]=useState(false);
  const[dir,sDir]=useState("f");
  const[data,setData]=useState({location:"서울 강남구",bizType:"카페",deposit:"80,000,000",monthlyRent:"3,500,000",rentType:"월세",sizes:["small"],extra:""});
  const nav=(t,d="f")=>{sDir(d);sTr(true);setTimeout(()=>{sPg(t);sTr(false);},280);};
  const order=["main","loc","map","biz","budget","size","extra","loading","done","report"];
  const labels={"main":"메인","loc":"위치 선택","map":"지도 범위","biz":"업종 선택","budget":"예산 입력","size":"입지 크기","extra":"추가사항","loading":"분석 중","done":"분석 완료","report":"리포트"};
  const ci=order.indexOf(pg);
  const goPrev=()=>{if(ci>0)nav(order[ci-1],"b");};
  const goNext=()=>{if(ci<order.length-1)nav(order[ci+1],"f");};
  const pages={
    main:<MainPage onStart={()=>nav("loc")}/>,
    loc:<SearchPage step={1} title={<>원하는 위치를<br/>선택해 주세요</>} placeholder="주소, 상호명을 검색" presetValue="서울 강남구" tags={["서울 강남구","강남역 2호선","압구정 로데오 거리","대치동","강남역 사거리","양재천"]} activeTag="서울 강남구" onBack={()=>nav("main","b")} onNext={()=>nav("map")}/>,
    map:<MapPage onBack={()=>nav("loc","b")} onNext={()=>nav("biz")}/>,
    biz:<SearchPage step={2} title={<>원하는 업종을<br/>선택해 주세요</>} placeholder="업종을 검색해 주세요" presetValue="카페" tags={["카페","백반/한정식","아이스크림/빙수","중국집","일반 유흥 주점","치킨"]} activeTag="카페" onBack={()=>nav("map","b")} onNext={()=>nav("budget")}/>,
    budget:<BudgetPage data={data} setData={setData} onBack={()=>nav("biz","b")} onNext={()=>nav("size")}/>,
    size:<SizePage data={data} setData={setData} onBack={()=>nav("budget","b")} onNext={()=>nav("extra")}/>,
    extra:<ExtraPage setData={setData} onBack={()=>nav("size","b")} onNext={()=>nav("loading")}/>,
    loading:<LoadingPage onDone={()=>nav("done")}/>,
    done:<DonePage onReport={()=>nav("report")}/>,
    report:<ReportPage data={data} onBack={()=>nav("done","b")}/>,
  };
  return(<div style={{minHeight:"100vh",display:"flex",flexDirection:"column",justifyContent:"center",alignItems:"center",background:"#111827",fontFamily:"'Pretendard',-apple-system,BlinkMacSystemFont,'Noto Sans KR',sans-serif"}}>
    <div style={{position:"fixed",top:16,left:"50%",transform:"translateX(-50%)",background:"rgba(255,255,255,0.08)",color:"rgba(255,255,255,0.5)",padding:"5px 14px",borderRadius:20,fontSize:11,letterSpacing:2,zIndex:100}}>DEMO</div>
    <div style={{width:PW,height:PH,borderRadius:44,overflow:"hidden",position:"relative",boxShadow:"0 0 0 3px #333,0 0 0 5px #1a1a1a,0 25px 80px rgba(0,0,0,0.6)",background:"#fff"}}><div style={{width:"100%",height:"100%",transition:"all .28s ease",opacity:tr?0:1,transform:tr?(dir==="f"?"translateX(40px)":"translateX(-40px)"):"translateX(0)"}}>{pages[pg]}</div></div>
    {/* External nav */}
    <div style={{display:"flex",alignItems:"center",gap:20,marginTop:20}}>
      <button onClick={goPrev} disabled={ci===0} style={{width:40,height:40,borderRadius:20,border:"1px solid rgba(255,255,255,0.15)",background:ci===0?"transparent":"rgba(255,255,255,0.1)",color:ci===0?"rgba(255,255,255,0.2)":"rgba(255,255,255,0.7)",cursor:ci===0?"not-allowed":"pointer",display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,transition:"all .2s"}}>←</button>
      <div style={{textAlign:"center",minWidth:100}}>
        <div style={{fontSize:13,fontWeight:600,color:"rgba(255,255,255,0.7)"}}>{labels[pg]}</div>
        <div style={{fontSize:11,color:"rgba(255,255,255,0.35)",marginTop:2}}>{ci+1} / {order.length}</div>
      </div>
      <button onClick={goNext} disabled={ci===order.length-1} style={{width:40,height:40,borderRadius:20,border:"1px solid rgba(255,255,255,0.15)",background:ci===order.length-1?"transparent":"rgba(255,255,255,0.1)",color:ci===order.length-1?"rgba(255,255,255,0.2)":"rgba(255,255,255,0.7)",cursor:ci===order.length-1?"not-allowed":"pointer",display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,transition:"all .2s"}}>→</button>
    </div>
    <style>{`@import url('https://cdn.jsdelivr.net/gh/orioncactus/pretendard/dist/web/static/pretendard.css');*{box-sizing:border-box;margin:0;padding:0}input::placeholder{color:#9CA3AF}input[type=range]{-webkit-appearance:none;appearance:none;background:#e0e0e0;border-radius:2px;outline:none}input[type=range]::-webkit-slider-thumb{-webkit-appearance:none;appearance:none;width:20px;height:20px;border-radius:50%;background:#4A6CF7;cursor:pointer;border:3px solid #fff;box-shadow:0 2px 6px rgba(0,0,0,0.2)}`}</style>
  </div>);
}
